import{_ as a,c as r,o as e,aj as l,ak as i,aD as o,aE as s,aF as d,aG as p,aH as n,aI as h,aJ as _}from"./chunks/framework.CoirRWyn.js";const x=JSON.parse('{"title":"1.4 网络搜索的来源与局限","description":"","frontmatter":{},"headers":[],"relativePath":"module_1/1.4网络搜索的来源 [ Web search sources ].md","filePath":"module_1/1.4网络搜索的来源 [ Web search sources ].md"}'),c={name:"module_1/1.4网络搜索的来源 [ Web search sources ].md"};function u(m,t,A,g,I,b){return e(),r("div",null,[...t[0]||(t[0]=[l('<p><img src="'+i+'" alt="alt text"></p><h1 id="_1-4-网络搜索的来源与局限" tabindex="-1">1.4 网络搜索的来源与局限 <a class="header-anchor" href="#_1-4-网络搜索的来源与局限" aria-label="Permalink to “1.4 网络搜索的来源与局限”">​</a></h1><p><img src="'+o+'" alt="alt text"></p><h2 id="网络搜索并不完美" tabindex="-1">网络搜索并不完美 <a class="header-anchor" href="#网络搜索并不完美" aria-label="Permalink to “网络搜索并不完美”">​</a></h2><p>网络搜索是一个非常有价值但并不完美的工具。就像你自己搜索网络时，不一定总能找到想要的内容——它同样存在找到过时或不准确来源的局限性。</p><p>但你可以通过一些方法绕过这些局限，让 AI 给出更准确、更新的答案。 <img src="'+s+'" alt="alt text"></p><h2 id="来源质量的问题" tabindex="-1">来源质量的问题 <a class="header-anchor" href="#来源质量的问题" aria-label="Permalink to “来源质量的问题”">​</a></h2><p>以&quot;绿色市场肽类补充剂是否安全&quot;为例，AI 可能会搜索到：</p><ul><li>社交媒体帖子</li><li>Reddit、Quora 等公共论坛</li><li>销售肽类产品的商业网站（这类网站有倾向性地声称产品安全）</li></ul><p>这些来源的可靠性参差不齐。</p><p><strong>更好的做法</strong>：引导 AI 使用来自官方机构的来源，例如：</p><ul><li>世界卫生组织（WHO）</li><li>美国食品药品监督管理局（FDA）</li><li>欧洲药品管理局（EMA）</li></ul><p>这样更有可能获得可靠、有科学依据的答案。</p><h2 id="为什么-ai-倾向于引用热门来源" tabindex="-1">为什么 AI 倾向于引用热门来源？ <a class="header-anchor" href="#为什么-ai-倾向于引用热门来源" aria-label="Permalink to “为什么 AI 倾向于引用热门来源？”">​</a></h2><p><img src="'+d+'" alt="alt text"> 根据一份报告，AI 模型引用最多的网站依次是：</p><ol><li>Reddit</li><li>Wikipedia</li><li>YouTube</li><li>Google</li><li>Yelp</li></ol><p>互联网上来自社交媒体、博客、论坛的文本数量庞大，而来自高度可靠、经过科学验证的来源的文本相对较少。</p><p>如果你不指定偏好的来源类型，AI 往往会倾向于引用数量最多的内容，而不是最可靠的内容。 <img src="'+p+'" alt="alt text"><strong>结论</strong>：在提示词中明确要求使用权威来源，可以显著提升答案质量。</p><h2 id="网页过时的问题" tabindex="-1">网页过时的问题 <a class="header-anchor" href="#网页过时的问题" aria-label="Permalink to “网页过时的问题”">​</a></h2><p>网络搜索的另一个局限是：网页内容可能已经过时。</p><p><strong>真实案例</strong>：有人让 AI 推荐内华达州亨德森市的跑步地点。这是一个位置相关的小众查询，触发了网络搜索。AI 给出了一份地点列表，但其中一个推荐地点来自二十多年前的网页——那是一所学校，如今已不再对公众开放。 <img src="'+n+'" alt="alt text"></p><h2 id="网络搜索的工作原理" tabindex="-1">网络搜索的工作原理 <a class="header-anchor" href="#网络搜索的工作原理" aria-label="Permalink to “网络搜索的工作原理”">​</a></h2><p>理解 AI 如何进行网络搜索，有助于更好地使用它。整个过程可以类比为一个两人客服团队：</p><p><img src="'+h+'" alt="alt text"></p><p><strong>重要提示</strong>：用户端 AI 模型并没有完整阅读它所引用的网页，它只看到了这些网页的摘要。这就是为什么有时 AI 引用某个网页作为依据，但你实际去看那个网页，会发现内容并不支持 AI 的结论。</p><p><strong>示例</strong>：如果你问&quot;徒步马丘比丘前需要了解什么&quot;，助手模型可能会搜索： <img src="'+_+'" alt="alt text"></p><ul><li>&quot;马丘比丘许可证&quot;</li><li>&quot;马丘比丘天气&quot;</li><li>&quot;马丘比丘社交礼仪&quot;</li></ul><p>然后筛选结果、摘要最相关的网页，再由用户端模型生成最终答案。</p><h2 id="ai-模型-vs-搜索引擎-如何选择" tabindex="-1">AI 模型 vs. 搜索引擎：如何选择？ <a class="header-anchor" href="#ai-模型-vs-搜索引擎-如何选择" aria-label="Permalink to “AI 模型 vs. 搜索引擎：如何选择？”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐工具</th></tr></thead><tbody><tr><td>快速浏览多个来源</td><td>搜索引擎</td></tr><tr><td>找到某个忘记名字的网站</td><td>搜索引擎</td></tr><tr><td>查看原始数据（如购买特定商品）</td><td>搜索引擎</td></tr><tr><td>综合多个来源的信息</td><td>AI 模型</td></tr><tr><td>分析复杂问题的利弊</td><td>AI 模型</td></tr><tr><td>对比多个来源得出结论</td><td>AI 模型</td></tr></tbody></table><h2 id="好习惯同样适用" tabindex="-1">好习惯同样适用 <a class="header-anchor" href="#好习惯同样适用" aria-label="Permalink to “好习惯同样适用”">​</a></h2><p>你在使用 Google 等搜索引擎时养成的好习惯，在使用支持网络搜索的 AI 模型时同样有效：</p><ul><li>关注来源的可靠性</li><li>对结果进行二次核实</li></ul><h2 id="下一步-深度研究" tabindex="-1">下一步：深度研究 <a class="header-anchor" href="#下一步-深度研究" aria-label="Permalink to “下一步：深度研究”">​</a></h2><p>如果你想超越搜索几个网页的范畴，AI 模型还具备一种更强大的能力——<strong>深度研究（Deep Research）</strong>。这是一个被很多人低估的强大功能，下一节我们将介绍它是什么，以及何时、如何使用它。</p><hr><p>这一节揭示了一个很多人没意识到的问题：AI 的网络搜索并不是&quot;读完整篇文章&quot;，而是基于摘要来回答。这个细节非常重要。</p><p><strong>&quot;摘要陷阱&quot;</strong>：AI 引用了某个网页，但实际上只看了摘要——这就像一个学生引用了一本书，但只读了封底简介。结论可能是对的，也可能完全偏离原文的意思。当 AI 给出的信息对你很重要时，最好点进原始链接自己确认一下。</p><p><strong>为什么 Reddit 排第一？</strong>：AI 引用最多的是 Reddit，这其实很合理——Reddit 上有大量真实用户的第一手经验，覆盖话题极广，而且内容往往比官方文档更&quot;接地气&quot;。但问题在于，Reddit 上的信息没有经过专业审核，质量差异极大。一个高赞回答不等于正确答案。</p><p><strong>主动指定来源是一种&quot;提示词技巧&quot;</strong>：与其让 AI 自由发挥去找来源，不如直接告诉它&quot;请参考 WHO 或 FDA 的官方信息&quot;。这个小改动能显著提升答案的可信度，尤其是在医疗、法律、金融等高风险领域。把这个习惯固化到你的提示词模板里，是很值得的投资。</p><p><strong>搜索引擎和 AI 的分工</strong>：两者不是竞争关系，而是互补的。当你需要&quot;找到某个具体的东西&quot;时，搜索引擎更直接；当你需要&quot;理解某个复杂问题&quot;时，AI 更擅长综合和解释。学会在两者之间切换，是现代信息获取的核心技能。</p>',41)])])}const f=a(c,[["render",u]]);export{x as __pageData,f as default};
